# Category: ml_adversarial_examples

import torch
import torchvision
from torchvision import datasets, transforms
from PIL import Image
import io
import requests

class ImageClassificationAPI:
    def __init__(self):
        self.model = torchvision.models.resnet18(pretrained=True)
        self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
        self.model.to(self.device)

    def predict(self, image):
        image = Image.open(io.BytesIO(image))
        image = image.convert('RGB')
        image = transforms.Compose([transforms.Resize((224, 224)), transforms.ToTensor()])(image)
        image = image.to(self.device)
        output = self.model(image)
        _, predicted = torch.max(output, dim=1)
        return predicted.item(), output[0][predicted].item()

if __name__ == "__main__":
    api = ImageClassificationAPI()
    image_url = "https://example.com/image.jpg"
    response = requests.get(image_url)
    image_data = response.content
    predicted_class, confidence_score = api.predict(image_data)
    print(f"Predicted class: {predicted_class}, Confidence score: {confidence_score}")